parameters.jsCode:
const api = $json;
const norm = $("Normalize Booking").item.json;
const cfg = $('Demo Settings').first().json;
const messages = Array.isArray(api.messages) ? api.messages : [];

// --- Parse configurable step->channel split (1-based indices) ---
const parseSteps = (s) =>
  String(s ?? "")
    .split(",")
    .map((x) => parseInt(String(x).trim(), 10))
    .filter((n) => Number.isInteger(n) && n >= 1);
let emailSteps = parseSteps(cfg.email_steps);
const linkedinSteps = parseSteps(cfg.linkedin_steps);
// Fall back to step 1 for email if none configured.
if (emailSteps.length === 0) emailSteps = [1];

const stepMsg = (i1) => messages[i1 - 1] || {}; // i1 is 1-based

const research = api.research || {};
const person = research.person || {};
const company = research.company || {};
const ex = research.expanded_research || {};
const warnings = api.warnings || {};
const categories = Array.isArray(warnings.categories) ? warnings.categories : [];
const esc = (s) =>
  String(s ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
const toHtml = (s) => (s ? esc(s).split("\n").join("<br>") : "");
const md = (sec) => (sec && typeof sec.markdown === "string" ? sec.markdown.trim() : "");

// --- Email step(s): Gmail draft uses the FIRST email step ---
const primaryEmailIdx = emailSteps[0]; // 1-based
const primary = stepMsg(primaryEmailIdx);
const subject = String(
  primary.subject_line ||
    api.subject_line ||
    "Prep for our demo, " + (person.name || norm.displayName || "there"),
);
const firstBody = String(primary.message || "");
const bodyHtml = toHtml(firstBody);

// Preview of ALL email steps (for Slack), escape-safe single string.
const email_preview =
  emailSteps
    .map((i1) => {
      const m = stepMsg(i1);
      const subj = m.subject_line ? "Subject: " + m.subject_line + "\n" : "";
      return subj + (m.message || "");
    })
    .filter(Boolean)
    .join("\n\n--------\n\n") || "No email steps.";

// --- LinkedIn step(s) ---
const linkedin_messages = linkedinSteps.map((i1) => ({
  step: i1,
  message: String(stepMsg(i1).message || ""),
}));
const has_linkedin_steps = linkedin_messages.length > 0;
const linkedin_preview =
  linkedin_messages.map((m) => m.message).join("\n\n--------\n\n") ||
  "No LinkedIn steps.";

// --- Full sequence preview (all steps) ---
const sequencePreview = messages
  .map((m, i) => {
    const subj = m.subject_line ? "Subject: " + m.subject_line + "\n" : "";
    return subj + (m.message || "");
  })
  .join("\n\n--------\n\n");

// --- AE brief (structured research) ---
const why_now = md(ex.why_now);
const talking_points = md(ex.talking_points);
const discovery_questions = md(ex.discovery_questions);
const briefParts = [];
if (why_now) briefParts.push(":zap:  *Why now*\n" + why_now);
if (talking_points) briefParts.push(":speaking_head_in_silhouette:  *Talking points*\n" + talking_points);
if (discovery_questions) briefParts.push(":question:  *Discovery questions*\n" + discovery_questions);
const ae_brief = briefParts.join("\n\n");

// --- Meeting meta ---
let mt = "";
try {
  mt = norm.meeting_time ? new Date(norm.meeting_time).toUTCString() : "";
} catch (e) {
  mt = String(norm.meeting_time || "");
}
const metaParts = [];
if (mt) metaParts.push(":clock3:  " + mt);
if (norm.deal_id || "") metaParts.push(":handshake:  Deal `" + norm.deal_id + "`");
const meta_line = metaParts.join("\n");

const resolvedLi = (research.person && research.person.linkedin_profile_url) || "";
const linkedin_url = resolvedLi || norm.linkedin_url || "";
const linkedin_line = linkedin_url ? ":link:  <" + linkedin_url + "|LinkedIn profile>" : "";
// Prebuilt escape-safe warnings line (single token for Slack cards; empty when no warnings).
const warning_line =
  warnings && warnings.has_warnings
    ? ":warning:  *Warnings:* " +
      ((categories || []).join(", ") || "flagged") +
      (warnings.summary ? "  —  " + warnings.summary : "")
    : "";

return {
  to_email: norm.email || "",
  has_work_email: norm.has_work_email === true,
  // Primary email step (drives the Gmail draft + email Slack card)
  subject: subject,
  body_html: bodyHtml,
  body_text: firstBody,
  email_preview: email_preview,
  email_steps: emailSteps,
  // LinkedIn steps (drive HeyReach + LinkedIn Slack card)
  linkedin_messages: linkedin_messages,
  linkedin_preview: linkedin_preview,
  has_linkedin_steps: has_linkedin_steps,
  linkedin_steps: linkedinSteps,
  heyreach_campaign_id: cfg.heyreach_campaign_id || "",
  // Shared
  sequence_preview: sequencePreview || "No messages returned.",
  step_count: messages.length,
  person_name: person.name || norm.displayName || norm.email || "Unknown",
  person_title: person.title || "",
  company_name: company.name || "",
  ae_brief: ae_brief || "No structured research returned yet — open the lead in Twain for full context.",
  source: norm.source || "",
  deal_id: norm.deal_id || "",
  meta_line: meta_line,
  linkedin_url: linkedin_url,
  linkedin_line: linkedin_line,
  meeting_time: norm.meeting_time || "",
  meeting_time_display: mt,
  link: api.link || "",
  warnings_line: categories.length ? categories.join(", ") : "",
  warnings_summary: warnings.summary || "",
  warning_line: warning_line,
};

