parameters.jsCode:
const src = $json.body ?? $json ?? {};
const PERSONAL = ["gmail.com","googlemail.com","outlook.com","hotmail.com","live.com","msn.com","yahoo.com","ymail.com","icloud.com","me.com","mac.com","proton.me","protonmail.com","aol.com","gmx.com","gmx.net","zoho.com","pm.me","mail.com","yandex.com"];
const DEMO_TERMS = ["demo"];
const str = (v) => (v === undefined || v === null) ? "" : String(v);
const firstNonEmpty = (...vals) => { for (const v of vals) { const s = str(v).trim(); if (s) return s; } return ""; };

// --- Detect provider (order matters: most specific first) ---
let source = "generic";
if (src.payload && (src.payload.scheduled_event || src.payload.uri || src.event === "invitee.created" || src.payload.email)) source = "calendly";
else if (src.guest || src.slot || (src.event && src.event.start) || src.crm) source = "chili_piper";
else if (src.properties || src.dealId !== undefined || src.engagementId !== undefined || src.objectId !== undefined) source = "hubspot_meetings";
else if (src.kind === "calendar#event" || (src.start && Array.isArray(src.attendees)) || src.iCalUID) source = "google_calendar";

// --- Calendly LinkedIn from Q&A (best effort) ---
const qaLinkedin = () => {
  const qa = src.payload && Array.isArray(src.payload.questions_and_answers) ? src.payload.questions_and_answers : [];
  for (const item of qa) {
    const q = str(item && (item.question || item.q)).toLowerCase();
    if (q.includes("linkedin")) return str(item && (item.answer || item.a)).trim();
  }
  return "";
};

// --- Google Calendar: pick the prospect attendee (not the host/organizer) ---
const gcalAttendee = () => {
  const att = Array.isArray(src.attendees) ? src.attendees : [];
  const prospect = att.find((a) => a && a.self !== true && a.organizer !== true && a.responseStatus !== "declined");
  return prospect || att[0] || null;
};
const gcalLinkedin = () => {
  const liRe = /https?:\/\/([\w-]+\.)*linkedin\.com\/(in|pub|company)\/[^\s"'<>)\]]+/i;
  const liScrape = (String(src.description||"") + " " + String(src.location||"")).match(liRe);
  return liScrape ? liScrape[0] : "";
};

// --- Per-source extraction with generic-flat fallback (all off `src`) ---
const p = src.payload || {};
const props = src.properties || {};
const gAtt = source === "google_calendar" ? gcalAttendee() : null;

const email = firstNonEmpty(
  p.email,
  src.guest && src.guest.email, src.fields && src.fields.email,
  props.email,
  gAtt && gAtt.email, source === "google_calendar" ? (src.creator && src.creator.email) : "",
  src.email
).toLowerCase();

const name = firstNonEmpty(
  p.name,
  src.guest && src.guest.name, src.fields && src.fields.name,
  src.firstName && src.lastName ? (src.firstName + " " + src.lastName) : "",
  props.firstname && props.lastname ? (props.firstname + " " + props.lastname) : "",
  props.firstname,
  gAtt && gAtt.displayName,
  src.name, src.displayName, src.invitee_name
);

const meeting_time = firstNonEmpty(
  p.scheduled_event && p.scheduled_event.start_time,
  src.event && src.event.start, src.slot && src.slot.start, src.startTime,
  props.hs_meeting_start_time,
  src.start && (src.start.dateTime || src.start.date),
  src.meeting_time, src.start_time
);

const meeting_title = firstNonEmpty(
  p.scheduled_event && p.scheduled_event.name,
  source === "google_calendar" ? src.summary : "",
  src.event && src.event.name, src.meetingType, src.fields && src.fields.meetingType, src.slot && src.slot.name,
  props.hs_meeting_title, props.meeting_name, src.subject,
  src.meeting_type, src.title, src.event_type, src.eventType
);

const linkedin_url = firstNonEmpty(
  source === "calendly" ? qaLinkedin() : "",
  source === "google_calendar" ? gcalLinkedin() : "",
  p.linkedin, p.linkedin_url, p.linkedin_profile_url,
  src.guest && src.guest.linkedin,
  src.linkedin, src.linkedin_url, src.linkedin_profile_url,
  props.linkedin, props.linkedin_url
);

const deal_id = firstNonEmpty(
  src.crm && src.crm.dealId,
  src.dealId, props.deal_id, src.associatedDealId,
  p.deal_id,
  src.deal_id
);

const stable_id = firstNonEmpty(
  p.scheduled_event && p.scheduled_event.uri, p.uri,
  src.bookingId, src.eventId, src.event && src.event.id,
  src.engagementId, src.objectId, props.hs_object_id,
  source === "google_calendar" ? (src.id || src.iCalUID) : "",
  src.id, src.uid, src.booking_id, src.event_id
);

const uid = stable_id || (email + "|" + meeting_time);
const email_domain = (email.split("@")[1] || "").toLowerCase();
const is_personal_email = PERSONAL.includes(email_domain);
const has_work_email = Boolean(email) && !is_personal_email;
const has_linkedin_url = Boolean(linkedin_url);

const t = meeting_title.toLowerCase();
const is_demo = !meeting_title ? true : DEMO_TERMS.some((term) => t.includes(term));

return {
  source: source,
  uid: uid,
  email: email,
  displayName: name,
  meeting_time: meeting_time,
  meeting_title: meeting_title,
  is_demo: is_demo,
  campaign_id: ($('Demo Settings').first().json.campaign_id || "REPLACE_WITH_DEMO_CAMPAIGN_ID"),
  linkedin_url: linkedin_url,
  deal_id: deal_id,
  email_domain: email_domain,
  is_personal_email: is_personal_email,
  has_linkedin_url: has_linkedin_url,
  has_work_email: has_work_email
};

// Resolve LinkedIn URL from the provider response.
// Adjust the field below to match YOUR provider's response shape.
const resp = $json || {};
const linkedin_url = resp.linkedin_url ?? resp.linkedin_profile_url ?? resp.url ?? resp.contact?.linkedin_url ?? resp.profile?.linkedin_url ?? resp.person?.linkedin_url ?? resp.data?.linkedin_url ?? resp.response?.linkedin_url ?? "";

// Carry forward all normalized fields, overriding only the LinkedIn ones.
const n = $('Normalize Booking').item.json;
return {
  ...n,
  linkedin_url: linkedin_url,
  has_linkedin_url: Boolean(linkedin_url)
};

